// assets
import { CloudLightning, Layers, Puzzle, Sparkles } from "lucide-react";

// constants
const featureData = [
  {
    title: "Cool Animations",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led the way to an adjoining.",
    icon: Sparkles,
    color: "bg-blue-500"
  },
  {
    title: "Fast & Easy Work",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led the way to an adjoining.",
    icon: Puzzle,
    color: "bg-yellow-500"
  },
  {
    title: "Quick Result",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led the way to an adjoining.",
    icon: Layers,
    color: "bg-green-500"
  },
  {
    title: "Creative Design",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led the way to an adjoining.",
    icon: CloudLightning,
    color: "bg-cyan-500"
  }
];

//  ------------------------------ | FEATURE - 8 | ------------------------------  //

export default function Feature8() {
  return (
    <section className="py-20 md:py-28">
      <div className="container mx-auto px-4">
        {/* Header Section */}
        <div className="mb-8 lg:mb-12">
          <h2 className="mb-6">Key Features</h2>
          <p className="text-muted-foreground text-lg">
            At half-past eight the door opened, the policeman appeared and
            requesting them to follow him, led way to an adjoining hall.
          </p>
        </div>

        {/* Features Grid */}
        <div className="grid grid-cols-12 gap-6">
          {featureData.map((item, index) => (
            <div key={index} className="col-span-12 md:col-span-6 flex gap-6">
              <div
                className={`flex size-20 shrink-0 items-center justify-center rounded-xl text-white ${item.color}`}
              >
                <item.icon size={40} strokeWidth={1.5} />
              </div>
              <div className="flex flex-col gap-2">
                <h5>{item.title}</h5>
                <p className="text-muted-foreground text-lg">
                  {item.description}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
